-- ============================================================
-- Case Workflow Report - Create table + insert all 3596 records
-- Schema: mstr
-- ============================================================

DROP TABLE IF EXISTS mstr.case_workflow_report CASCADE;

CREATE TABLE mstr.case_workflow_report (
    case_id                                     INTEGER PRIMARY KEY,
    entity_id                                   VARCHAR(100),
    entity_name                                 VARCHAR(200),
    sector_name                                 VARCHAR(200),
    isic_code                                   VARCHAR(100),
    isic_description                            TEXT,
    group_id                                    VARCHAR(100),
    client_group_name                           VARCHAR(200),
    country_of_domicile                         VARCHAR(200),
    case_status                                 VARCHAR(100),
    ageing                                      VARCHAR(100),
    cancellation_reason                         VARCHAR(500),
    cra_status                                  VARCHAR(100),
    created_on                                  TIMESTAMP,
    modified_on                                 TIMESTAMP,
    entity_classification                       VARCHAR(200),
    review_type                                 VARCHAR(100),
    review_subtype                              VARCHAR(100),
    maker_psid                                  VARCHAR(50),
    maker_name                                  VARCHAR(100),
    climate_risk_grading_status                 VARCHAR(100),
    physical_risk_brag                          VARCHAR(100),
    transition_risk_brag                        VARCHAR(100),
    advisor_psid                                VARCHAR(50),
    advisor_name                                VARCHAR(100),
    date_of_submission_to_climate_risk_advisor  TIMESTAMP,
    date_of_rejection_by_climate_risk_advisor   TIMESTAMP,
    approver_approved_on                        TIMESTAMP,
    approver_name                               VARCHAR(100),
    approver_psid                               VARCHAR(50),
    approver_rejected_on                        TIMESTAMP,
    assessment_type                             VARCHAR(100),
    date_of_submission_to_rm                    TIMESTAMP,
    rm_rejected_on                              TIMESTAMP,
    rm_recommended_on                           TIMESTAMP,
    rm_psid                                     VARCHAR(50),
    rm_name                                     VARCHAR(100),
    rm_approved_on                              TIMESTAMP,
    primary_booking_location_country            VARCHAR(100),
    questionnaire_version                       VARCHAR(50),
    case_assessment_review_reason               VARCHAR(500),
    current_assignee_name                       VARCHAR(100),
    current_assignee_psid                       VARCHAR(50),
    checker_name                                VARCHAR(100),
    checker_psid                                VARCHAR(50),
    ca_name                                     VARCHAR(100),
    ca_psid                                     VARCHAR(50),
    case_initiator_name                         VARCHAR(100),
    case_initiator_role                         VARCHAR(100),
    case_initiator_psid                         VARCHAR(50),
    date_of_submission_to_checker               TIMESTAMP,
    date_of_rejection_by_checker                TIMESTAMP,
    total_days_initiation_before_maker          INTEGER DEFAULT 0,
    total_days_with_maker_team                  INTEGER DEFAULT 0,
    total_days_with_checker_team                INTEGER DEFAULT 0,
    total_days_with_climate_risk_advisor_team   INTEGER DEFAULT 0,
    total_days_with_rm                          INTEGER DEFAULT 0,
    total_days_with_climate_risk_approver       INTEGER DEFAULT 0,
    total_tat_for_case                          INTEGER DEFAULT 0,
    total_rejections_by_checker                 INTEGER DEFAULT 0,
    total_rejections_by_climate_risk_advisor    INTEGER DEFAULT 0,
    total_rejections_by_rm                      INTEGER DEFAULT 0,
    total_rejections_by_climate_risk_approver   INTEGER DEFAULT 0
);

-- ============================================================
-- INSERT all records
-- ============================================================


-- ============================================================
-- Indexes
-- ============================================================
CREATE INDEX idx_cwf_entity_id ON mstr.case_workflow_report (entity_id);
CREATE INDEX idx_cwf_sector ON mstr.case_workflow_report (sector_name);
CREATE INDEX idx_cwf_country ON mstr.case_workflow_report (country_of_domicile);
CREATE INDEX idx_cwf_case_status ON mstr.case_workflow_report (case_status);
CREATE INDEX idx_cwf_cra_status ON mstr.case_workflow_report (cra_status);
CREATE INDEX idx_cwf_climate_grading ON mstr.case_workflow_report (climate_risk_grading_status);
CREATE INDEX idx_cwf_group ON mstr.case_workflow_report (client_group_name);
CREATE INDEX idx_cwf_assessment_type ON mstr.case_workflow_report (assessment_type);
